package com.sassybutler.alarm

/**
 * PhonemeEncoder — Converts English text to Kokoro phoneme ID sequences.
 *
 * ⚠ GENERATED FILE — edit tools/generate_phoneme_encoder.py, not this.
 *
 * Pipeline (mirrors kokoro-onnx's tokenizer):
 *   text → normalized words → IPA phoneme string (espeak-ng lexicons,
 *   one per English dialect; the caller picks the dialect matching the
 *   Kokoro voice family) → per-char vocab IDs → [0, ids…, 0]
 *
 * The lexicons cover every word in the app's speech templates plus
 * number/time words. Unknown words fall back to rough letter rules —
 * re-run the generator when adding new sassy lines.
 */
class PhonemeEncoder {

    enum class Dialect { EN_US, EN_GB }

    /** Encode [text] into Kokoro phoneme IDs, 0-padded at both ends. */
    fun encode(text: String, dialect: Dialect = Dialect.EN_US): LongArray {
        val phonemes = textToPhonemeString(preprocess(text), dialect)
        val ids = phonemes.mapNotNull { ch -> VOCAB[ch.toString()] }

        return LongArray(ids.size + 2).also { arr ->
            ids.forEachIndexed { i, id -> arr[i + 1] = id }
        }
    }

    // ─── Preprocessing ───────────────────────────────────────────────────

    private fun preprocess(text: String): String {
        var t = text
            // "7:07" → "seven oh seven", "7:00" → "seven o'clock"
            .replace(Regex("(\\d{1,2}):(\\d{2})")) { m ->
                val h = m.groupValues[1].toInt()
                val min = m.groupValues[2].toInt()
                expandNumber(h) + when {
                    min == 0   -> " o'clock"
                    min < 10   -> " oh " + expandNumber(min)
                    else       -> " " + expandNumber(min)
                }
            }
            .replace("AM", " ay em ")
            .replace("PM", " pee em ")
        t = t.replace(Regex("(\\d+)")) { expandNumber(it.value.toIntOrNull() ?: 0) }
        return t.lowercase()
            .replace(Regex("[^a-z' ,.!?]"), " ")
            .replace(Regex("\\s+"), " ")
            .trim()
    }

    private fun expandNumber(n: Int): String {
        val ones = listOf("zero","one","two","three","four","five","six","seven",
                          "eight","nine","ten","eleven","twelve","thirteen",
                          "fourteen","fifteen","sixteen","seventeen","eighteen","nineteen")
        val tens = listOf("","","twenty","thirty","forty","fifty",
                          "sixty","seventy","eighty","ninety")
        return when {
            n < 20   -> ones[n]
            n < 100  -> tens[n / 10] + if (n % 10 != 0) " ${ones[n % 10]}" else ""
            n < 1000 -> "${ones[n / 100]} hundred" +
                        if (n % 100 != 0) " ${expandNumber(n % 100)}" else ""
            else     -> n.toString()
        }
    }

    // ─── Words → IPA phoneme string ──────────────────────────────────────

    private fun textToPhonemeString(text: String, dialect: Dialect): String {
        val lexicon = when (dialect) {
            Dialect.EN_US -> LEXICON_EN_US
            Dialect.EN_GB -> LEXICON_EN_GB
        }
        val sb = StringBuilder()
        for (token in text.split(" ")) {
            if (token.isEmpty()) continue
            // Peel sentence punctuation off the word so "night." → word + "."
            val punct = token.takeLastWhile { it in ",.!?" }
            val word  = token.dropLast(punct.length)

            if (word.isNotEmpty()) {
                if (sb.isNotEmpty()) sb.append(' ')
                sb.append(lexicon[word] ?: fallbackG2p(word))
            }
            sb.append(punct)
        }
        return sb.toString()
    }

    /**
     * Rough rule-based fallback for words missing from the lexicon.
     * Understandable at best — extend the generator's word list instead.
     */
    private fun fallbackG2p(word: String): String {
        val sb = StringBuilder()
        var i = 0
        while (i < word.length) {
            val rule = G2P_RULES.entries.firstOrNull { word.startsWith(it.key, i) }
            if (rule != null) {
                sb.append(rule.value); i += rule.key.length
            } else {
                sb.append(LETTER_FALLBACK[word[i]] ?: ""); i++
            }
        }
        return sb.toString()
    }

